/**
 * GENERIC CHUNKER & FORMATTER
 * Smart dispatching for Web, FAQ, and Product Sheets
 */

function fnv1a64Hex(input) {
  let hash = 0xcbf29ce484222325n;
  const prime = 0x100000001b3n;
  const s = String(input ?? '');
  for (let i = 0; i < s.length; i++) {
    hash ^= BigInt(s.charCodeAt(i));
    hash = (hash * prime) & 0xffffffffffffffffn;
  }
  return hash.toString(16).padStart(16, '0');
}

// Generic chunking logic here...
return $input.all();

// Stoplist of URLs to filter out (Client Specific)
const STOPLIST = [
  'https://www.clientwebsite.com/cart',
  'https://www.clientwebsite.com/checkout',
  'https://www.clientwebsite.com/login'
];

const stoplistSet = new Set(STOPLIST);
const links = $json.links || [];

const filteredLinks = links.filter(item => !stoplistSet.has(item.url)).map(item => ({ json: { link: item.url } }));
return filteredLinks;
